#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Polynomial node structure
typedef struct PolyNode {
 int coeff; // Coefficient of the term
 int expo; // Exponent of the term
 struct PolyNode *next; // Pointer to next term
} PolyNode;

// Create a new node
PolyNode* createNode(int coeff, int expo) {
 PolyNode *newNode = (PolyNode *)malloc(sizeof(PolyNode));
 if (newNode == NULL) {
 printf("Memory allocation failed\n");
 exit(1);
 }
 newNode->coeff = coeff;
 newNode->expo = expo;
 newNode->next = NULL;
 return newNode;
}

// Insert term maintaining decreasing exponent order
PolyNode* insertTerm(PolyNode *poly, int coeff, int expo) {
 if (coeff == 0) return poly;

 // Check if same exponent exists at head
 if (poly != NULL && expo == poly->expo) {
 poly->coeff += coeff;
 if (poly->coeff == 0) {
 PolyNode *temp = poly;
 poly = poly->next;
 free(temp);
 }
 return poly;
 }

 // Insert at beginning if new expo is largest
 if (poly == NULL || expo > poly->expo) {
 PolyNode *newNode = createNode(coeff, expo);
 newNode->next = poly;
 return newNode;
 }

 // Find correct position
 PolyNode *current = poly;
 while (current->next != NULL && current->next->expo > expo) {
 current = current->next;
 }

 // Check for duplicate exponent
 if (current->next != NULL && current->next->expo == expo) {
 current->next->coeff += coeff;
 if (current->next->coeff == 0) {
 PolyNode *temp = current->next;
 current->next = temp->next;
 free(temp);
 }
 } else {
 PolyNode *newNode = createNode(coeff, expo);
 newNode->next = current->next;
 current->next = newNode;
 }
 return poly;
}

// Display polynomial
void displayPolynomial(PolyNode *poly) {
 if (poly == NULL) {
 printf("0\n");
 return;
 }

 PolyNode *current = poly;
 int first = 1;

 while (current != NULL) {
 int absCoeff = abs(current->coeff);

 if (!first && current->coeff > 0) printf(" + ");
 else if (!first && current->coeff < 0) printf(" -");

 if (first && current->coeff < 0) printf("-");

 if (current->expo == 0) {
 printf("%d", absCoeff);
 } else if (current->expo == 1) {
 printf("%dx", absCoeff == 1 ? 1 : absCoeff);
 } else {
 printf("%dx^%d", absCoeff == 1 ? 1 : absCoeff, current->expo);
 }

 first = 0;
 current = current->next;
 }
 printf("\n");
}

// Polynomial addition: merge-like algorithm
PolyNode* addPolynomials(PolyNode *p1, PolyNode *p2) {
 PolyNode *result = NULL;

 while (p1 != NULL && p2 != NULL) {
 if (p1->expo > p2->expo) {
 result = insertTerm(result, p1->coeff, p1->expo);
 p1 = p1->next;
 } else if (p1->expo < p2->expo) {
 result = insertTerm(result, p2->coeff, p2->expo);
 p2 = p2->next;
 } else {
 // Same exponent - add coefficients
 result = insertTerm(result, p1->coeff + p2->coeff, p1->expo);
 p1 = p1->next;
 p2 = p2->next;
 }
 }

 // Copy remaining terms
 while (p1 != NULL) {
 result = insertTerm(result, p1->coeff, p1->expo);
 p1 = p1->next;
 }
 while (p2 != NULL) {
 result = insertTerm(result, p2->coeff, p2->expo);
 p2 = p2->next;
 }

 return result;
}

// Polynomial multiplication
PolyNode* multiplyPolynomials(PolyNode *p1, PolyNode *p2) {
 PolyNode *result = NULL;
 PolyNode *ptr1 = p1;

 while (ptr1 != NULL) {
 PolyNode *ptr2 = p2;
 while (ptr2 != NULL) {
 int newCoeff = ptr1->coeff * ptr2->coeff;
 int newExpo = ptr1->expo + ptr2->expo;
 result = insertTerm(result, newCoeff, newExpo);
 ptr2 = ptr2->next;
 }
 ptr1 = ptr1->next;
 }

 return result;
}

// Evaluate polynomial at given x
double evaluatePolynomial(PolyNode *poly, double x) {
 double result = 0;
 PolyNode *current = poly;

 while (current != NULL) {
 result += current->coeff * pow(x, current->expo);
 current = current->next;
 }

 return result;
}

// Free polynomial memory
void freePolynomial(PolyNode *poly) {
 PolyNode *current = poly;
 while (current != NULL) {
 PolyNode *temp = current;
 current = current->next;
 free(temp);
 }
}

// Create polynomial from array of terms
PolyNode* createPolynomialFromTerms(int terms[][2], int n) {
 PolyNode *poly = NULL;
 for (int i = 0; i < n; i++) {
 poly = insertTerm(poly, terms[i][0], terms[i][1]);
 }
 return poly;
}

int main() {
 // Create P(x) = 5x^3 + 4x^2 + 2x + 1
 int terms1[][2] = {{5, 3}, {4, 2}, {2, 1}, {1, 0}};
 PolyNode *p1 = createPolynomialFromTerms(terms1, 4);

 // Create Q(x) = 3x^3 + 2x + 7
 int terms2[][2] = {{3, 3}, {2, 1}, {7, 0}};
 PolyNode *p2 = createPolynomialFromTerms(terms2, 3);

 printf("P(x) = ");
 displayPolynomial(p1);

 printf("Q(x) = ");
 displayPolynomial(p2);

 // Addition
 PolyNode *sum = addPolynomials(p1, p2);
 printf("P(x) + Q(x) = ");
 displayPolynomial(sum);

 // Multiplication
 PolyNode *product = multiplyPolynomials(p1, p2);
 printf("P(x) * Q(x) = ");
 displayPolynomial(product);

 // Evaluation
 printf("P(2) = %.2f\n", evaluatePolynomial(p1, 2));

 // Demonstrate sparse polynomial
 int sparseTerms[][2] = {{3, 1000}, {2, 1}, {7, 0}};
 PolyNode *sparse = createPolynomialFromTerms(sparseTerms, 3);
 printf("Sparse (3x^1000 + 2x + 7) = ");
 displayPolynomial(sparse);

 // Free memory
 freePolynomial(p1);
 freePolynomial(p2);
 freePolynomial(sum);
 freePolynomial(product);
 freePolynomial(sparse);

 return 0;
}

import java.util.*;

class PolyNode {
 int coeff;
 int expo;
 PolyNode next;

 PolyNode(int coeff, int expo) {
 this.coeff = coeff;
 this.expo = expo;
 this.next = null;
 }
}

public class Polynomial {
 private PolyNode head;

 public Polynomial() {
 this.head = null;
 }

 public boolean isEmpty() {
 return head == null;
 }

 public void insertTerm(int coeff, int expo) {
 if (coeff == 0) return;

 // Check if same exponent at head
 if (head != null && expo == head.expo) {
 head.coeff += coeff;
 if (head.coeff == 0) {
 head = head.next;
 }
 return;
 }

 // Insert at beginning if new expo is largest
 if (head == null || expo > head.expo) {
 PolyNode newNode = new PolyNode(coeff, expo);
 newNode.next = head;
 head = newNode;
 return;
 }

 // Find position
 PolyNode current = head;
 while (current.next != null && current.next.expo > expo) {
 current = current.next;
 }

 // Check for duplicate
 if (current.next != null && current.next.expo == expo) {
 current.next.coeff += coeff;
 if (current.next.coeff == 0) {
 current.next = current.next.next;
 }
 } else {
 PolyNode newNode = new PolyNode(coeff, expo);
 newNode.next = current.next;
 current.next = newNode;
 }
 }

 public void display() {
 if (head == null) {
 System.out.println("0");
 return;
 }

 StringBuilder sb = new StringBuilder();
 PolyNode current = head;
 boolean first = true;

 while (current != null) {
 int absCoeff = Math.abs(current.coeff);

 if (!first && current.coeff > 0) sb.append(" + ");
 else if (!first && current.coeff < 0) sb.append(" -");

 if (first && current.coeff < 0) sb.append("-");

 if (current.expo == 0) {
 sb.append(absCoeff);
 } else if (current.expo == 1) {
 sb.append(absCoeff == 1 ? "x" : absCoeff + "x");
 } else {
 sb.append(absCoeff == 1 ? "x^" + current.expo : 
 absCoeff + "x^" + current.expo);
 }

 first = false;
 current = current.next;
 }

 System.out.println(sb.toString());
 }

 public static Polynomial add(Polynomial p1, Polynomial p2) {
 Polynomial result = new Polynomial();
 PolyNode ptr1 = p1.head;
 PolyNode ptr2 = p2.head;

 while (ptr1 != null && ptr2 != null) {
 if (ptr1.expo > ptr2.expo) {
 result.insertTerm(ptr1.coeff, ptr1.expo);
 ptr1 = ptr1.next;
 } else if (ptr1.expo < ptr2.expo) {
 result.insertTerm(ptr2.coeff, ptr2.expo);
 ptr2 = ptr2.next;
 } else {
 result.insertTerm(ptr1.coeff + ptr2.coeff, ptr1.expo);
 ptr1 = ptr1.next;
 ptr2 = ptr2.next;
 }
 }

 while (ptr1 != null) {
 result.insertTerm(ptr1.coeff, ptr1.expo);
 ptr1 = ptr1.next;
 }

 while (ptr2 != null) {
 result.insertTerm(ptr2.coeff, ptr2.expo);
 ptr2 = ptr2.next;
 }

 return result;
 }

 public static Polynomial multiply(Polynomial p1, Polynomial p2) {
 Polynomial result = new Polynomial();
 PolyNode ptr1 = p1.head;

 while (ptr1 != null) {
 PolyNode ptr2 = p2.head;
 while (ptr2 != null) {
 result.insertTerm(ptr1.coeff * ptr2.coeff, 
 ptr1.expo + ptr2.expo);
 ptr2 = ptr2.next;
 }
 ptr1 = ptr1.next;
 }

 return result;
 }

 public double evaluate(double x) {
 double result = 0;
 PolyNode current = head;

 while (current != null) {
 result += current.coeff * Math.pow(x, current.expo);
 current = current.next;
 }

 return result;
 }

 // Main method for testing
 public static void main(String[] args) {
 // Create P(x) = 5x^3 + 4x^2 + 2x + 1
 Polynomial p1 = new Polynomial();
 p1.insertTerm(5, 3);
 p1.insertTerm(4, 2);
 p1.insertTerm(2, 1);
 p1.insertTerm(1, 0);

 // Create Q(x) = 3x^3 + 2x + 7
 Polynomial p2 = new Polynomial();
 p2.insertTerm(3, 3);
 p2.insertTerm(2, 1);
 p2.insertTerm(7, 0);

 System.out.print("P(x) = ");
 p1.display();

 System.out.print("Q(x) = ");
 p2.display();

 // Addition
 Polynomial sum = add(p1, p2);
 System.out.print("P(x) + Q(x) = ");
 sum.display();

 // Multiplication
 Polynomial product = multiply(p1, p2);
 System.out.print("P(x) * Q(x) = ");
 product.display();

 // Evaluation
 System.out.println("P(2) = " + p1.evaluate(2));

 // Sparse polynomial
 Polynomial sparse = new Polynomial();
 sparse.insertTerm(3, 1000);
 sparse.insertTerm(2, 1);
 sparse.insertTerm(7, 0);
 System.out.print("Sparse (3x^1000 + 2x + 7) = ");
 sparse.display();
 }
}
